class Solution:
    def countWays(self, nums: List[int]) -> int:
        nums.sort()
        n = len(nums)
        res = 0

        # Case 1: Select no students
        if nums[0] > 0:
            res += 1

        # Case 2: Select all students
        if nums[-1] < n:
            res += 1

        # Case 3: Select some students
        for i in range(1, n):
            if nums[i - 1] < i and nums[i] > i:
                res += 1

        return res
